output.sparql:
PREFIX ps: <http://www.wikidata.org/prop/statement/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX pq: <http://www.wikidata.org/prop/qualifier/>
SELECT DISTINCT ?coach ?coachLabel ?teamLabel WHERE {
  ?team wdt:P118 wd:Q1215884 .
  ?team p:P286 ?position .
  ?position ps:P286 ?coach .
  FILTER NOT EXISTS {
    ?position pq:P582 []
  }
  .
  ?coach wdt:P31 wd:Q5 .
  ?coach wdt:P54 ?playerTeam .
  ?playerTeam wdt:P118 wd:Q1215884 .
  OPTIONAL {
    ?coach rdfs:label ?coachLabel
    FILTER(LANG(?coachLabel) = "en")
  }
  OPTIONAL {
    ?team rdfs:label ?teamLabel
    FILTER(LANG(?teamLabel) = "en")
  }
}

args.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX pq: <http://www.wikidata.org/prop/qualifier/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?coach ?coachLabel ?teamLabel WHERE {
  ?team wdt:P118 wd:Q1215884 .
  ?team p:P286 ?position .
  ?position ps:P286 ?coach .
  FILTER NOT EXISTS { ?position pq:P582 _:endDate . }

  ?coach wdt:P31 wd:Q5 .
  ?coach wdt:P54 ?playerTeam .
  ?playerTeam wdt:P118 wd:Q1215884 .

  OPTIONAL { ?coach rdfs:label ?coachLabel . FILTER (LANG(?coachLabel) = "en") }
  OPTIONAL { ?team rdfs:label ?teamLabel . FILTER (LANG(?teamLabel) = "en") }
}
